declare @message nvarchar(4000)
select @message = ''

        &CommandControlLocationLotShowing;
        &VisibleFieldGridDetailShowing;

select @message as message
return

script.text:
      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien]/[so_luong]) : 0) : [gia])',

    gia: '[gia]:=[gia_nt]*[$ty_gia]',
    tien_nt: '[tien_nt]:=[so_luong]*[gia_nt]',
    tien: '[tien]:=[so_luong]*[gia]',
    tien_tg: '[tien]:=[tien_nt]*[$ty_gia]',

    t_so_luong: ['t_so_luong', 'so_luong'],
    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien'],
    gia_nt_sl2: '[gia_nt2]:=([gia_nt2] == 0 ? ([so_luong] != 0 ? ([tien_nt2]/[so_luong]) : 0) : [gia_nt2])',
    tien_nt2: '[tien_nt2]:=[so_luong]*[gia_nt2]',
    t_tien_nt2: ['t_tien_nt2', 'tien_nt2']
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_dvcs', 'stt_rec'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho', 'ma_vi_tri', ['action', 'Decimal', o.grid.get_element().parentForm._action == 'Edit' ? 1 : 0]], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'ma_vi_tri', 'ma_lo', 'dvt', 'so_luong', ['action', 'Decimal', o.grid.get_element().parentForm._action == 'Edit' ? 1 : 0]], o.grid.$h, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_vt', 'ma_kho', 'ma_lo', 'he_so', ['action', 'Decimal', o.grid.get_element().parentForm._action == 'Edit' ? 1 : 0]], o.grid.$h, true);}
function onChange$GridVoucherDetail$Reason(o) {o.grid.request(o, 'Reason', 'Reason', ['ma_nx'], o.grid.$h, true);}
/* </flatten> */
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt, g.$a.tien], [g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien]);
      &InternalTransportFormScriptChange;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia, g.$a.tien_nt, g.$a.tien], [g.$a.t_tien_nt, g.$a.t_tien], null, 'tien_nt');
      break;
    case 'tien_nt':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia]);
      g.validExpression(o, [g.$a.tien_tg], [g.$a.t_tien_nt,g.$a.t_tien]);
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien], [g.$a.t_tien], null, 'tien');
      break;
    case 'tien':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, null, [g.$a.t_tien]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (!(g.validRowExpression('so_luong', '([gia_ton] != 3) || ([$loai_ct] == "7") || ([so_luong] != 0)'))) break;
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location) g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")');
      break;
    case 'Lookup':
      var r = g._activeRow, c = true, a = ['vt', 'kho', 'vi_tri', 'lo'];
      if (f._action == 'View' || r == -1 || !r) break;
      for (var i = 0; i < a.length; i++) {
        var v1 = g._getItem(r, g._getColumnOrder('ma_' + a[i])), v2 = g._getItem(r, g._getColumnOrder('ten_' + a[i] + '%l'));
        if ((v1.addControl || v1.label) && !v2.checked) {
          c = false;
          break;
        }
      }
      if (!c || !f.validFields('ngay_lct')) break;
      if (g._getItemValue(r, g._getColumnOrder('ma_vt')) != '') {
        g._siteCode = g._getItemValue(r, g._getColumnOrder('ma_kho'));
        if (!g._onchangeForeignCurrencyPriceExpression) g._onchangeForeignCurrencyPriceExpression = [g.$a.gia, g.$a.tien_nt, g.$a.tien];
        g.showForm('ViewReceiptFilter');
      }
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ngay_lct')) break;
      switch (e.type.Value) {
        case '10':
          g.showForm('ISMRFilter');
          break;
        case '30':
          if (!g._tracked) break;
          g.showForm('ISPhysicalFilter');
          break;
        default:
          break;
      }
      break;
    case 'Copying':
      var fields = 'stt_rec_pn, stt_rec0pn, stt_rec_yc, stt_rec0yc';
    &ScriptWhenTransactionEmptyField;
      if (fields != '') set$Voucher$EmptyExternalField(g, fields);
      break;
    case 'ImportData':
      if (f._action == 'View') break;
      g.showForm('ISDetailImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['ma_lo', result[2].Value, '', null],
        ['dvt', result[3].Value, '', true],
        ['he_so', result[4].Value, null, null],
        ['tk_vt', result[5].Value, '', true],
        ['gia_ton', result[6].Value, null, null],
        ['vi_tri_yn', [result[7].Value, t], null, null],
        ['lo_yn', result[8].Value, null, null],
        ['ton13', result[9].Value, null, null]
      ]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, '', true], ['ton13', result[1].Value, null, null]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [
        ['tk_vt', result[0].Value, '', true],
        ['ma_vi_tri', '', '', null],
        ['vi_tri_yn', result[1].Value, null, null],
        ['ton13', result[2].Value, null, null]
      ]);
      break;
    case 'Location':
    case 'Lot':
      g.setItemGridBehavior(o, [['ton13', result[0].Value, null, null]]);
      break;
    case 'Reason':
      g.setItemGridBehavior(o, [['tk_du', result[0].Value, '', true]]);
      break;
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$RowChange(g, f) {g.executeAggregate([g.$a.t_so_luong, g.$a.t_tien, g.$a.t_tien_nt&InternalTransportFormScriptRowChange;]);}

      &DowloadScript;
      &ScriptGridStockRequest;
      &ScriptEmptyExternalField;
      &ScriptInsertRetrieveItems;

grid.response:
&XMLGetReason;
if exists(select 1 from dmvt where ma_vt = @ma_vt) begin declare @unitCode varchar(32), @stock numeric(25, 5) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end exec FastBusiness$Current$Stock 0, @ma_vt, @ma_kho, @ma_vi_tri, '', @$stt_rec, 1, @voucherCode, @unitCode, @action, 2, @stock output exec FastBusiness$Voucher$Issue$Item @unitCode, @ma_vt, @stock, @voucherCode, @@userID, @@admin, 1, @ma_kho, @ma_vi_tri, @$stt_rec, @action, 2 return end
declare @unitCode varchar(32), @rate numeric(25, 5), @stock numeric(25, 5) if exists(select 1 from dmqddvt where dvt = @dvt and (ma_vt = @ma_vt or ma_vt = '*')) begin select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end select @rate = he_so from dmqddvt where dvt = @dvt and (ma_vt = @ma_vt or ma_vt = '*') exec FastBusiness$Current$Stock 1, @ma_vt, @ma_kho, @ma_vi_tri, @ma_lo, @$stt_rec, @rate, @voucherCode, @unitCode, @action, 2, @stock output select isnull(@rate, 1) as he_so, @stock as stock return end
declare @unitCode varchar(32), @stock numeric(25, 5) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end if exists(select 1 from dmkho where ma_kho = @ma_kho and ma_dvcs = @unitCode&SiteCheck;) begin exec FastBusiness$Current$Stock 2, @ma_vt, @ma_kho, '', @ma_lo, @$stt_rec, @he_so, @voucherCode, @unitCode, @action, 2, @stock output exec FastBusiness$Voucher$Issue$Site @unitCode, @ma_vt, @ma_kho, @stock return end
&CreateTicket; select @ticket as value return
&XMLGridStockResponse;
